export class GetFeaturedProjects {
  constructor(private readonly projectRepository: IProjectRepository) {}

  async execute(
    input: GetFeaturedProjectsInput
  ): Promise<Either<DomainError, ProjectSummaryDTO[]>> {
    try {
      const projects = await this.projectRepository.findFeatured();
      const dtos = projects.map(p => this.toDTO(p, input.locale));
      return right(dtos);
    } catch (error) {
      // If repository throws, wrap in DomainError
      return left(new DomainError('Failed to fetch featured projects'));
    }
