      id: project.id.toString(),
      slug: project.slug.toString(),
      title: project.title.get(locale),
      caption: project.caption.get(locale),
      coverImage: {
        url: project.coverImage.url.toString(),
        alt: project.coverImage.alt.get(locale)
      },
      theme: project.theme?.get(locale),
      skills: project.skills.map(s => s.name.get(locale)),
      publishedAt: project.period.start.toISOString()
    };
  }
}
