import { ContactMessageDTO } from '../dtos/ContactMessageDTO';

export interface SendContactMessageInput {
  name: string;
  email: string;
  message: string;
}

export class SendContactMessage {
  constructor(private readonly emailService: IEmailService) {}

  async execute(
    input: SendContactMessageInput
  ): Promise<Either<ValidationError | DomainError, void>> {
    // Validate name
    if (!input.name?.trim()) {
      return left(new ValidationError('Name is required'));
    }

    // Validate email format (simple regex)
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!input.email?.trim() || !emailRegex.test(input.email)) {
      return left(new ValidationError('Valid email is required'));
    }

    // Validate message
    if (!input.message?.trim()) {
      return left(new ValidationError('Message is required'));
    }

    const dto: ContactMessageDTO = {
      name: input.name.trim(),
      email: input.email.trim(),
      message: input.message.trim()
    };

    // Send via email service
    const result = await this.emailService.send(dto);

    if (result.isLeft()) {
      return left(result.value);
    }

    return right(undefined);
  }
}
