**New Implementation:**
```typescript
static create(raw?: string): Either<ValidationError, Slug> {
  const trimmed = raw?.trim();
  const normalized = trimmed?.toLowerCase() ?? '';

  const { isValid, error } = Validator.of(normalized)
    .length(3, Number.MAX_SAFE_INTEGER, 'Slug must be at least 3 characters.')
    .regex(Slug.SLUG_REGEX, 'Slug must be kebab-case (lowercase letters, numbers and hyphens only).')
    .validate();

  if (!isValid && error) {
    return left(new ValidationError({
      code: Slug.ERROR_CODE,
      message: error,
    }));
  }

  return right(new Slug(normalized));
}
```

