### 1. Implement Either.collect utility (packages/core/src/shared/either.ts)

Add the following function to the either.ts file after the existing left/right helpers:

```typescript
/**
 * Collects an array of Either values into a single Either.
 * Returns Left with the first error encountered, or Right with all values.
 * 
 * @example
 * const results = [Right(1), Right(2), Right(3)];
 * const collected = Either.collect(results); // Right([1, 2, 3])
 * 
 * @example
 * const results = [Right(1), Left(error), Right(3)];
 * const collected = Either.collect(results); // Left(error)
 */
export function collect<L, R>(eithers: Either<L, R>[]): Either<L, R[]> {
  const values: R[] = [];

  for (const either of eithers) {
    if (either.isLeft()) {
      return left(either.value);
    }
    values.push(either.value);
  }

  return right(values);
}
```

