// Validator.of check remains as-is
const { error, isValid } = Validator.of(startDt.ms)
  .refine((startMs) => startMs <= endDt.ms, 'Start date must be before or equal to end date.')
  .validate();

if (!isValid && error)
  return left(new ValidationError({ code: DateRange.ERROR_CODE, message: error }));

return right(new DateRange(startDt, endDt));
```

**Without end date - keep as single check.**

## Success Criteria

