import { describe, it, expect } from 'vitest';
import { left, right, collect, Either } from '../../src/shared/either';
import { ValidationError } from '../../src/shared/errors';

describe('Either.collect', () => {
  it('should return Right with all values when all are Right', () => {
    const eithers = [right(1), right(2), right(3)];
    const result = collect(eithers);

    expect(result.isRight()).toBe(true);
    if (result.isRight()) {
      expect(result.value).toEqual([1, 2, 3]);
    }
  });

  it('should return Left with first error when one is Left', () => {
    const error = new ValidationError({ code: 'TEST', message: 'Test error' });
    const eithers = [right(1), left(error), right(3)];
    const result = collect(eithers);

    expect(result.isLeft()).toBe(true);
    if (result.isLeft()) {
      expect(result.value).toBe(error);
    }
  });

  it('should return Right with empty array for empty input', () => {
    const result = collect([]);

    expect(result.isRight()).toBe(true);
    if (result.isRight()) {
      expect(result.value).toEqual([]);
    }
  });

  it('should stop at first Left and not process remaining', () => {
    let sideEffectCount = 0;
    const createRight = (n: number): Either<ValidationError, number> => {
      sideEffectCount++;
      return right(n);
    };

    const error = new ValidationError({ code: 'ERR', message: 'Error' });
    const eithers = [createRight(1), left(error), createRight(3)];

    const result = collect(eithers);

    expect(result.isLeft()).toBe(true);
    expect(sideEffectCount).toBe(1); // Only first Right was processed
  });
});
```

