import {
  DomainError,
  Either,
  NotFoundError,
  UnauthorizedError,
  left,
  right,
} from '@repo/core/shared';
import { AccessPolicy, IUserRepository } from '@repo/core/identity';

import { UseCase } from '../../shared/UseCase';

export interface EnsureAdminInput {
  userId: string;
}

export class EnsureAdmin extends UseCase<
  EnsureAdminInput,
  void,
  UnauthorizedError | NotFoundError | DomainError
> {
  constructor(private readonly userRepository: IUserRepository) {
    super();
  }

  async execute(
    input: EnsureAdminInput,
  ): Promise<Either<UnauthorizedError | NotFoundError | DomainError, void>> {
    try {
      const user = await this.userRepository.findById(input.userId);
      if (!user) return left(new NotFoundError({ userId: input.userId }));

      if (!AccessPolicy.isAdmin(user)) {
        return left(
          new UnauthorizedError({
            message: 'User does not have admin privileges',
            userId: input.userId,
          }),
        );
      }

      return right(undefined);
    } catch {
      return left(
        new DomainError('FETCH_FAILED', { message: 'Failed to verify admin status' }),
      );
    }
  }
}
