**3. Create getAuthenticatedUser() server helper**

Create `apps/web/src/lib/auth/getAuthenticatedUser.ts`:
```typescript
import { Email } from '@repo/core/identity';
import { User } from '@repo/core/identity';
import { left, right, type Either } from '@repo/core/shared';
import { DomainError } from '@repo/core/shared';

import { createClient } from '../supabase/server';
import { getContainer } from '@repo/infra';

/**
 * Server-only helper to resolve the authenticated user from Supabase session.
 * Returns Either<DomainError, User | null>.
 * - right(null) if no session exists (unauthenticated)
 * - right(User) if authenticated and user exists in database
 * - left(DomainError) if database lookup fails or user invalid
 */
export async function getAuthenticatedUser(): Promise<Either<DomainError, User | null>> {
  const supabase = await createClient();

  const { data: { session }, error: sessionError } = await supabase.auth.getSession();

  if (sessionError || !session) {
    return right(null);
  }

  const emailResult = Email.create(session.user.email);
  if (emailResult.isLeft()) {
    return left(emailResult.value);
  }

  const container = getContainer();
  const userRepository = container.userRepository;

  const user = await userRepository.findByEmail(emailResult.value);

  if (!user) {
    return right(null);
  }

  return right(user);
}
```

**4. Update middleware.ts to protect admin routes**

Replace `apps/web/src/middleware.ts`:
```typescript
import createIntlMiddleware from 'next-intl/middleware';
import { NextRequest, NextResponse } from 'next/server';

import { routing } from './i18n/routing';
import { updateSession } from './lib/supabase/middleware';

const intlMiddleware = createIntlMiddleware(routing, {
  localeDetection: true,
});

export async function middleware(request: NextRequest) {
  // Update Supabase session
  const response = await updateSession(request);

  // Apply i18n routing
  const intlResponse = intlMiddleware(request);

  // Check if route is admin
  const pathname = request.nextUrl.pathname;
  const isAdminRoute = pathname.match(/^\/(en-US|es|pt-BR)\/admin/);

  if (isAdminRoute) {
    const supabase = await import('./lib/supabase/server').then(m => m.createClient());
    const client = await supabase();
    const { data: { session } } = await client.auth.getSession();

    if (!session) {
      // Extract locale from pathname
      const locale = pathname.split('/')[1];
      const loginUrl = new URL(`/${locale}/login`, request.url);
      loginUrl.searchParams.set('redirect', pathname);
      return NextResponse.redirect(loginUrl);
    }
  }

  // Merge i18n response with Supabase response
  if (intlResponse) {
    response.headers.set('x-middleware-cache', intlResponse.headers.get('x-middleware-cache') || '');
    response.headers.set('x-nextjs-matched-path', intlResponse.headers.get('x-nextjs-matched-path') || '');
  }

  return response;
}

export const config = {
  matcher: [
    '/',
    '/((?!api|_next|_vercel|.*\\..*).*)',
    '/(en-US|es|pt-BR)/:path*',
  ],
};
```

