import { redirect } from 'next/navigation';
import { getContainer } from '@repo/infra';
import { EnsureAdminUseCase } from '@repo/application/identity';

import { getAuthenticatedUser } from '~/lib/auth/getAuthenticatedUser';

export default async function AdminLayout({
  children,
  params: { locale },
}: {
  children: React.ReactNode;
  params: { locale: string };
}) {
  const userResult = await getAuthenticatedUser();

  if (userResult.isLeft() || !userResult.value) {
    redirect(`/${locale}/login?redirect=/${locale}/admin`);
  }

  const container = getContainer();
  const ensureAdmin = new EnsureAdminUseCase(container.userRepository);

  const ensureResult = await ensureAdmin.execute({ userId: userResult.value.id });

  if (ensureResult.isLeft()) {
    // User is not admin, redirect to home with error
    redirect(`/${locale}?error=unauthorized`);
  }

  return (
    <div className="min-h-screen">
      <nav className="bg-gray-800">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
          <div className="flex h-16 items-center justify-between">
            <div className="flex items-center">
              <span className="text-white font-bold">Admin Panel</span>
            </div>
          </div>
        </div>
      </nav>
      <main className="mx-auto max-w-7xl px-4 py-6 sm:px-6 lg:px-8">
        {children}
      </main>
    </div>
  );
}
